questions = [
  {"id":63,"domain":2,"subdomain":"2.1","objective":"Compare and contrast common threat actors and motivations","stem":"Which threat actor is MOST likely motivated by financial gain and operates like a business, providing ransomware-as-a-service?","options":{"A":"Nation-state","B":"Hacktivist","C":"Organized crime","D":"Insider threat"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Organized crime groups are primarily financially motivated and often operate sophisticated operations including ransomware-as-a-service (RaaS) platforms sold to affiliates.","A":"Nation-states are typically motivated by espionage, sabotage, or geopolitical objectives rather than direct financial gain.","B":"Hacktivists are motivated by ideological or political causes, not profit.","C":"Correct. Organized crime is financially motivated and increasingly operates RaaS and other cybercrime businesses.","D":"Insider threats may be financially motivated but are not the group that typically operates RaaS platforms."}},
  {"id":64,"domain":2,"subdomain":"2.1","objective":"Compare and contrast common threat actors and motivations","stem":"An employee who leaks confidential data to competitors in exchange for money is BEST described as which type of threat actor?","options":{"A":"Unintentional insider","B":"Nation-state actor","C":"Malicious insider","D":"Hacktivist"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"A malicious insider intentionally misuses their authorized access to cause harm, in this case selling data to competitors for personal financial gain.","A":"An unintentional insider causes harm through negligence or mistakes, not deliberate malice.","B":"Nation-state actors are government-sponsored threat groups; an individual employee is not.","C":"Correct. An employee deliberately leaking data for financial gain is a malicious insider.","D":"Hacktivists are motivated by ideology, not financial gain from selling corporate data."}},
  {"id":65,"domain":2,"subdomain":"2.1","objective":"Compare and contrast common threat actors and motivations","stem":"Which attribute BEST distinguishes a nation-state threat actor from other threat actors?","options":{"A":"They only target government networks","B":"They have significant resources, sophistication, and government sponsorship","C":"They are motivated exclusively by financial gain","D":"They exclusively use publicly available tools"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Nation-state actors are sponsored by governments and typically have extensive resources, advanced capabilities, and sophisticated long-term attack campaigns (APTs).","A":"Nation-states target many sectors including defense, energy, finance, and healthcare — not only government networks.","B":"Correct. Government sponsorship with substantial resources and high sophistication define nation-state actors.","C":"Nation-states are motivated by espionage, sabotage, and geopolitical goals — not primarily financial gain.","D":"Nation-states develop and use advanced custom tools (zero-days, APT toolkits), not just public tools."}},
  {"id":66,"domain":2,"subdomain":"2.1","objective":"Compare and contrast common threat actors and motivations","stem":"An attacker uses pre-built tools downloaded from the internet with no deep understanding of how they work. This attacker is BEST classified as:","options":{"A":"Nation-state","B":"Hacktivist","C":"Unskilled attacker (script kiddie)","D":"Organized crime"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"Script kiddies (unskilled attackers) use existing tools and exploit code without understanding the underlying mechanisms. They rely on others' work rather than developing their own capabilities.","A":"Nation-states have high sophistication and develop custom tools.","B":"Hacktivists have ideological motivations but may have varying skill levels.","C":"Correct. Script kiddies use pre-built tools without deep technical knowledge.","D":"Organized crime groups typically have higher skill levels and develop or purchase sophisticated tools."}},
  {"id":67,"domain":2,"subdomain":"2.1","objective":"Compare and contrast common threat actors and motivations","stem":"Which threat actor type is MOST likely to conduct a long-term, covert campaign to steal intellectual property from a defense contractor?","options":{"A":"Hacktivist","B":"Organized crime","C":"Nation-state (APT)","D":"Unskilled attacker"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Nation-state actors conduct Advanced Persistent Threats (APTs) — long-term, stealthy campaigns focused on high-value targets like defense contractors to steal sensitive IP.","A":"Hacktivists are motivated by ideology and typically conduct higher-profile, shorter-duration attacks.","B":"Organized crime focuses on financial gain (ransomware, fraud) rather than IP theft for national interests.","C":"Correct. Nation-state APT groups conduct patient, covert campaigns targeting high-value organizations.","D":"Unskilled attackers lack the capability to conduct sustained, covert operations."}},
  {"id":68,"domain":2,"subdomain":"2.1","objective":"Compare and contrast common threat actors and motivations","stem":"An employee installs unauthorized cloud storage software to share work files more conveniently. This is an example of:","options":{"A":"Malicious insider","B":"Shadow IT","C":"APT activity","D":"Social engineering"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Shadow IT refers to unauthorized hardware, software, or services used by employees without IT department knowledge or approval. It creates security risks even without malicious intent.","A":"A malicious insider intentionally causes harm; this employee is acting for convenience, not to cause damage.","B":"Correct. Unauthorized software installations by employees are classic shadow IT.","C":"APT is a sophisticated, long-term attack by a threat actor — not an employee convenience decision.","D":"Social engineering manipulates people into revealing information or taking actions; not applicable here."}},
  {"id":69,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker sends a fraudulent email to a company's CFO claiming to be the CEO and requesting a large wire transfer. This is BEST described as:","options":{"A":"Spear phishing","B":"Whaling","C":"Smishing","D":"Vishing"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Whaling specifically targets high-level executives (C-suite) with highly customized spear phishing attacks, often involving fake executive communications for financial fraud (BEC).","A":"Spear phishing targets specific individuals but is not specifically focused on executives.","B":"Correct. Whaling targets high-profile executives like CEOs and CFOs.","C":"Smishing uses SMS text messages as the attack vector.","D":"Vishing uses voice calls as the attack vector."}},
  {"id":70,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker sends text messages impersonating a bank and directing victims to a fake website. This is called:","options":{"A":"Phishing","B":"Vishing","C":"Smishing","D":"Spear phishing"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"Smishing is phishing conducted via SMS text messages. Attackers impersonate legitimate entities via text to direct victims to malicious links or collect information.","A":"Phishing uses email as the primary vector, not text messages.","B":"Vishing uses voice calls (phone calls) as the attack vector.","C":"Correct. Smishing uses SMS/text messages to conduct phishing attacks.","D":"Spear phishing targets specific individuals via email, not through SMS."}},
  {"id":71,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker compromises a legitimate website frequently visited by a target group, then infects visitors with malware. This is a:","options":{"A":"Drive-by download","B":"Watering hole attack","C":"Typosquatting attack","D":"Man-in-the-browser attack"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"A watering hole attack compromises websites that a target population frequently visits, then infects those visitors — similar to a predator waiting at a watering hole.","A":"Drive-by downloads occur when visiting any malicious site but are not specifically targeting a particular user group via their trusted sites.","B":"Correct. Watering hole attacks compromise sites frequented by the intended victims.","C":"Typosquatting registers misspelled domain names to catch users who make typing errors.","D":"Man-in-the-browser attacks inject malicious code into the browser to intercept transactions."}},
  {"id":72,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker registers the domain 'g00gle.com' hoping users mistype the real domain. This is:","options":{"A":"Watering hole attack","B":"DNS poisoning","C":"Typosquatting","D":"URL hijacking"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Typosquatting (also called URL hijacking) registers domains that resemble legitimate sites but contain typos or character substitutions, hoping to capture users who make mistakes.","A":"Watering hole attacks compromise legitimate sites; typosquatting registers lookalike domains.","B":"DNS poisoning corrupts DNS cache to redirect legitimate domain lookups; not the same as registering a fake domain.","C":"Correct. Registering a misspelled lookalike domain is typosquatting.","D":"URL hijacking is synonymous with typosquatting — both describe registering deceptive domain names."}},
  {"id":73,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"A malicious actor creates an open Wi-Fi access point named 'CoffeeShop_Free' near a legitimate coffee shop to intercept user traffic. This is called:","options":{"A":"Rogue access point","B":"Evil twin","C":"Wardriving","D":"Deauthentication attack"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"An evil twin is a rogue access point that mimics the name (SSID) of a legitimate network to trick users into connecting to the attacker's network.","A":"A rogue access point is any unauthorized AP; an evil twin specifically mimics a legitimate network's SSID.","B":"Correct. An evil twin mimics a legitimate network's SSID to capture user traffic.","C":"Wardriving involves driving around to identify wireless networks, not setting up a fake AP.","D":"A deauthentication attack forces clients off a network (often to push them toward an evil twin) but is not the fake AP itself."}},
  {"id":74,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker calls an employee pretending to be IT support and convinces them to reveal their password. This attack relies on:","options":{"A":"Technical exploitation","B":"Social engineering","C":"Brute force","D":"Credential stuffing"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"Social engineering manipulates people psychologically into performing actions or disclosing information. Impersonating IT support over the phone (vishing) is a classic social engineering technique.","A":"Technical exploitation uses software vulnerabilities, not human manipulation.","B":"Correct. Impersonating IT support to obtain a password is social engineering via vishing.","C":"Brute force tries all possible passwords automatically — no human interaction needed.","D":"Credential stuffing uses lists of stolen credentials to try on multiple sites."}},
  {"id":75,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker creates a fake emergency scenario to manipulate an employee into providing access. The fabricated scenario is known as:","options":{"A":"Tailgating","B":"Baiting","C":"Pretexting","D":"Quid pro quo"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Pretexting involves creating a fabricated scenario (pretext) to manipulate a target. The attacker invents a context to establish credibility and extract information or access.","A":"Tailgating (piggybacking) follows an authorized person through a secure door without authentication.","B":"Baiting uses the promise of something enticing (e.g., a found USB drive) to lure victims.","C":"Correct. Pretexting fabricates a scenario to manipulate the target.","D":"Quid pro quo attacks offer a service in exchange for information (e.g., fake IT help for a password)."}},
  {"id":76,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"An attacker exploits a vulnerability on the same day the vendor becomes aware of it. This is called a:","options":{"A":"Logic bomb","B":"Zero-day exploit","C":"Race condition","D":"Supply chain attack"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A zero-day exploit targets a vulnerability that is unknown to the vendor or for which no patch exists. It is exploited before the vendor can develop and release a fix.","A":"A logic bomb is malicious code that executes when specific conditions are met, unrelated to vendor awareness.","B":"Correct. A zero-day exploit targets a vulnerability before the vendor knows of it or releases a patch.","C":"A race condition occurs when system behavior depends on the sequence of events, which can be exploited.","D":"A supply chain attack targets the development or distribution process, not specifically an unpatched vulnerability."}},
  {"id":77,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which vulnerability occurs when a program writes data beyond the allocated memory buffer, potentially allowing code execution?","options":{"A":"SQL injection","B":"Integer overflow","C":"Buffer overflow","D":"Race condition"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"A buffer overflow occurs when a program writes more data to a buffer than it can hold, overwriting adjacent memory. Attackers can use this to overwrite return addresses and execute arbitrary code.","A":"SQL injection sends malicious SQL code to a database interpreter.","B":"Integer overflow occurs when a calculation exceeds the maximum value for a data type, potentially causing unexpected behavior.","C":"Correct. Buffer overflow writes past the end of an allocated buffer, potentially allowing code execution.","D":"A race condition exploits timing differences between competing processes."}},
  {"id":78,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"An attacker uses user-supplied input in a database query without proper sanitization, returning unauthorized data. This is:","options":{"A":"Cross-site scripting","B":"Command injection","C":"SQL injection","D":"LDAP injection"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"SQL injection occurs when user input is inserted into a SQL query without sanitization, allowing attackers to manipulate the query and access, modify, or delete database data.","A":"XSS injects malicious scripts into web pages viewed by other users; it targets the browser, not the database.","B":"Command injection inserts OS commands into an application input, targeting the operating system.","C":"Correct. SQL injection manipulates database queries through unsanitized user input.","D":"LDAP injection manipulates LDAP queries, not SQL database queries."}},
  {"id":79,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"A web application reflects user input directly back to the browser without sanitization, allowing attackers to inject scripts that run in victims' browsers. This is:","options":{"A":"Stored XSS","B":"Reflected XSS","C":"DOM-based XSS","D":"CSRF"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Reflected XSS occurs when user input is immediately reflected back in the server's response without sanitization. The malicious script is included in a crafted link and executes when the victim clicks it.","A":"Stored XSS persists the malicious script in the server's database, affecting all visitors.","B":"Correct. Reflected XSS reflects the malicious input immediately in the response.","C":"DOM-based XSS modifies the DOM environment in the victim's browser without server involvement.","D":"CSRF forces authenticated users to execute unwanted actions but does not inject scripts."}},
  {"id":80,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which attack forces an authenticated user to unknowingly submit a request to a web application using their existing session?","options":{"A":"Session hijacking","B":"Reflected XSS","C":"CSRF","D":"Clickjacking"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Cross-Site Request Forgery (CSRF) exploits the trust a website has in a user's browser, tricking the authenticated user into making an unintended request (e.g., transferring funds).","A":"Session hijacking steals a user's session token to impersonate them.","B":"Reflected XSS injects malicious scripts via crafted links; CSRF forces actions using existing sessions.","C":"Correct. CSRF tricks an authenticated user into submitting a forged request using their session.","D":"Clickjacking tricks users into clicking hidden elements on an overlaid page."}},
  {"id":81,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"A developer writes code where two processes compete for the same resource, and an attacker exploits the small window between a check and its use. This is a:","options":{"A":"Buffer overflow","B":"Race condition (TOCTOU)","C":"Integer overflow","D":"Use-after-free"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"A race condition (specifically TOCTOU — Time of Check, Time of Use) occurs when there is a gap between checking a condition and using a resource. An attacker can manipulate the resource in that gap.","A":"Buffer overflow writes past allocated memory boundaries, not a timing issue.","B":"Correct. TOCTOU is a race condition where the state changes between the check and the use.","C":"Integer overflow occurs when arithmetic exceeds maximum integer size.","D":"Use-after-free occurs when freed memory is accessed, not a competition between processes."}},
  {"id":82,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which vulnerability class allows an attacker to read data from adjacent memory by exploiting hardware-level CPU timing?","options":{"A":"Buffer overflow","B":"Side-channel attack","C":"Heap spray","D":"Return-oriented programming"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Side-channel attacks exploit physical characteristics like timing, power consumption, or electromagnetic emissions. Spectre and Meltdown are CPU side-channel vulnerabilities that leak data from protected memory.","A":"Buffer overflow writes past allocated memory, not a hardware timing attack.","B":"Correct. Side-channel attacks exploit observable physical characteristics of systems, such as CPU timing.","C":"Heap spray fills memory with shellcode, a code injection technique — not a side-channel attack.","D":"Return-oriented programming chains existing code fragments; it is a code reuse exploit technique."}},
  {"id":83,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which type of vulnerability is MOST commonly found in legacy systems that are no longer receiving security patches?","options":{"A":"Zero-day","B":"Known unpatched vulnerability","C":"Race condition","D":"Misconfiguration"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Legacy (unsupported) systems accumulate known unpatched vulnerabilities because vendors no longer release security updates, leaving documented vulnerabilities permanently exploitable.","A":"Zero-days are unknown to vendors; legacy systems have the opposite problem — known vulnerabilities with no patches.","B":"Correct. End-of-life systems have known vulnerabilities that will never be patched.","C":"Race conditions are code-level issues independent of system age.","D":"Misconfiguration is a setup error, not specific to legacy systems (though common in unmanaged legacy systems)."}},
  {"id":84,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"An IoT thermostat is deployed with its factory-default username and password still active. This represents which vulnerability type?","options":{"A":"Zero-day","B":"Default credentials","C":"Insecure protocols","D":"Missing patches"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"Default credentials (unchanged factory passwords) are a common IoT vulnerability. Attackers know default credentials for many devices and actively scan for devices still using them.","A":"Zero-day refers to an unknown, unpatched vulnerability — not credentials issues.","B":"Correct. Unchanged default credentials are one of the most common IoT vulnerabilities.","C":"Insecure protocols (like Telnet instead of SSH) are a separate vulnerability class.","D":"Missing patches address software vulnerabilities, not authentication issues."}},
  {"id":85,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A user's computer begins encrypting all local and network files and displays a ransom demand. The computer is infected with:","options":{"A":"Spyware","B":"Ransomware","C":"Rootkit","D":"Worm"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"Ransomware encrypts victim files and demands payment for the decryption key, making files inaccessible until the ransom is paid.","A":"Spyware silently collects and transmits user information; it does not encrypt files or demand ransom.","B":"Correct. Ransomware encrypts files and extorts payment for decryption.","C":"A rootkit hides malware presence from the OS; it doesn't typically encrypt files for ransom.","D":"A worm self-replicates across networks; it may carry ransomware but is not ransomware itself."}},
  {"id":86,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A type of malware that logs every keystroke on a victim's computer and sends the data to an attacker is called a:","options":{"A":"Rootkit","B":"Keylogger","C":"Backdoor","D":"Logic bomb"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"A keylogger records all keystrokes (including passwords and sensitive data) and transmits them to the attacker. It is commonly used to steal credentials.","A":"A rootkit hides malicious processes and files from the OS; it may contain a keylogger but is not one itself.","B":"Correct. A keylogger captures keystrokes to steal credentials and other sensitive data.","C":"A backdoor provides persistent unauthorized access to a system; it doesn't log keystrokes.","D":"A logic bomb executes malicious code when a specific condition is met (time, event), not a recording tool."}},
  {"id":87,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"Malware that hides itself and other malicious programs by intercepting and modifying OS calls is called a:","options":{"A":"Trojan","B":"Worm","C":"Rootkit","D":"Backdoor"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"A rootkit intercepts OS-level calls to hide its presence and the presence of other malware from security tools and the operating system itself.","A":"A Trojan disguises itself as legitimate software but doesn't specifically hide OS calls.","B":"A worm self-replicates across networks; it doesn't focus on hiding OS calls.","C":"Correct. Rootkits operate at the kernel level to intercept OS calls and hide malware.","D":"A backdoor provides unauthorized remote access but doesn't necessarily hide itself via OS call interception."}},
  {"id":88,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"An attacker sends a large volume of SYN packets to a server without completing the TCP handshake. This is called a:","options":{"A":"UDP flood","B":"Smurf attack","C":"SYN flood","D":"Ping of death"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"A SYN flood attack sends many TCP SYN packets without completing the three-way handshake. The server allocates resources for half-open connections, exhausting its capacity.","A":"A UDP flood sends large volumes of UDP packets to overwhelm a server; different from SYN-specific attacks.","B":"A Smurf attack broadcasts ICMP requests with a spoofed source IP to overwhelm the victim with replies.","C":"Correct. A SYN flood exploits the TCP handshake by never completing connections, exhausting server resources.","D":"Ping of death sends oversized ICMP packets to crash systems; a historical vulnerability."}},
  {"id":89,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"Which type of malware appears legitimate but contains hidden malicious functionality?","options":{"A":"Worm","B":"Virus","C":"Trojan","D":"Adware"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"A Trojan horse (Trojan) disguises itself as legitimate software but contains hidden malicious code. Users willingly install it, believing it to be benign.","A":"A worm self-replicates and spreads without user interaction or needing to hide as legitimate software.","B":"A virus attaches to legitimate files and spreads when those files are executed; it doesn't typically disguise itself as a useful program.","C":"Correct. A Trojan masquerades as legitimate software while hiding malicious functionality.","D":"Adware displays unwanted advertisements; it may be bundled with software but isn't defined by disguising malicious functionality."}},
  {"id":90,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"An attacker intercepts communication between a user and a web server, reading and potentially modifying the data in transit. This is a:","options":{"A":"Replay attack","B":"Man-in-the-middle (MITM) attack","C":"Eavesdropping","D":"Session hijacking"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A man-in-the-middle (MITM) attack positions the attacker between the communicating parties, intercepting and potentially modifying traffic without the parties' knowledge.","A":"A replay attack captures and retransmits legitimate authentication messages at a later time.","B":"Correct. MITM positions the attacker between two communicating parties to intercept and modify traffic.","C":"Eavesdropping (passive) only reads traffic; MITM can also modify data in transit.","D":"Session hijacking steals an established session token; it doesn't necessarily intercept the initial communication."}},
  {"id":91,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"Malware that operates only in memory, leaving no files on disk, is called:","options":{"A":"Rootkit","B":"Fileless malware","C":"Logic bomb","D":"Polymorphic malware"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Fileless malware resides entirely in memory (RAM) and uses legitimate system tools like PowerShell or WMI. Because it writes no files to disk, it evades many traditional signature-based AV tools.","A":"A rootkit hides malware using OS-level interception but typically has on-disk components.","B":"Correct. Fileless malware executes in memory only, leaving no files on disk.","C":"A logic bomb is triggered by a specific condition and may have on-disk components.","D":"Polymorphic malware changes its code signature to evade detection but still writes files to disk."}},
  {"id":92,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"Which attack replays previously captured authentication credentials to gain unauthorized access?","options":{"A":"Pass-the-hash","B":"Credential stuffing","C":"Replay attack","D":"Kerberoasting"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"A replay attack captures a valid authentication message (token, ticket, or credential) and retransmits it later to authenticate as the legitimate user.","A":"Pass-the-hash captures NTLM hashes and uses them directly without cracking — a specific type of replay for NTLM authentication.","B":"Credential stuffing uses breach-obtained username/password pairs against other services.","C":"Correct. A replay attack retransmits captured authentication data to gain unauthorized access.","D":"Kerberoasting requests Kerberos service tickets and cracks them offline to obtain service account passwords."}},
  {"id":93,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"An attacker poisons the ARP cache of a local network switch to redirect traffic through their machine. Which protocol is being abused?","options":{"A":"DNS","B":"DHCP","C":"ARP","D":"BGP"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"ARP (Address Resolution Protocol) poisoning sends fake ARP replies to associate the attacker's MAC address with a legitimate IP, redirecting local network traffic through the attacker.","A":"DNS poisoning corrupts DNS caches to redirect domain lookups, a different protocol.","B":"DHCP attacks (starvation/spoofing) target IP address assignment, not MAC-to-IP mapping.","C":"Correct. ARP poisoning corrupts the ARP cache to redirect local network traffic through the attacker.","D":"BGP hijacking manipulates internet routing tables at the ISP level."}},
  {"id":94,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"Which Windows attack steals NTLM password hashes and uses them directly to authenticate without cracking them?","options":{"A":"Kerberoasting","B":"Golden ticket attack","C":"Pass-the-hash","D":"Silver ticket attack"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Pass-the-hash (PtH) steals NTLM hashes from memory using tools like Mimikatz and uses them directly for authentication without needing to crack the plaintext password.","A":"Kerberoasting extracts Kerberos service tickets and cracks them offline for plaintext passwords.","B":"Golden ticket attacks forge Kerberos TGTs using the KRBTGT hash — different mechanism.","C":"Correct. Pass-the-hash uses stolen NTLM hashes for direct authentication without cracking.","D":"Silver ticket attacks forge Kerberos service tickets (TGS) for specific services."}},
  {"id":95,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"An attacker forges a Kerberos Ticket Granting Ticket (TGT) using the KRBTGT account hash, giving them persistent domain admin access. This is a:","options":{"A":"Pass-the-ticket","B":"Silver ticket attack","C":"Golden ticket attack","D":"Kerberoasting"},"correct_answer":"C","difficulty":4,"explanations":{"correct":"A golden ticket attack uses the compromised KRBTGT account's password hash to forge arbitrary TGTs with any privileges, providing persistent domain-wide access.","A":"Pass-the-ticket uses stolen legitimate Kerberos tickets; a golden ticket forges them.","B":"A silver ticket forges service-specific TGS tickets for a single service, not domain-wide TGTs.","C":"Correct. Golden tickets are forged TGTs using the KRBTGT hash, granting persistent domain admin access.","D":"Kerberoasting cracks service account passwords offline; it doesn't forge tickets."}},
  {"id":96,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"Network traffic shows a large number of outbound DNS queries to unusual domains at regular intervals. This MOST likely indicates:","options":{"A":"DDoS amplification attack","B":"DNS tunneling for command and control","C":"Zone transfer attempt","D":"DNS cache poisoning"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Regular, frequent DNS queries to unusual domains are a classic indicator of DNS tunneling, where malware uses DNS requests to communicate with a C2 server, bypassing firewalls that allow DNS traffic.","A":"DDoS amplification uses DNS for outbound spoofed queries targeting victims; the pattern here describes C2 traffic.","B":"Correct. Regular DNS queries to strange domains suggest DNS tunneling for C2 communication.","C":"A zone transfer attempt queries for all DNS records from a zone; it's a single bulk request, not regular small queries.","D":"DNS cache poisoning injects malicious records into resolver caches; it doesn't produce this traffic pattern."}},
  {"id":97,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which mitigation technique divides a network into separate zones to contain the spread of a breach?","options":{"A":"ACL","B":"Patching","C":"Network segmentation","D":"Encryption"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Network segmentation divides a network into isolated zones (e.g., DMZ, VLANs), so that a compromised segment cannot directly reach other network segments, limiting breach propagation.","A":"ACLs control traffic between segments but segmentation is the architectural technique that creates the isolated zones.","B":"Patching fixes known vulnerabilities but doesn't limit lateral movement within a flat network.","C":"Correct. Segmentation creates isolated network zones to contain breaches and limit lateral movement.","D":"Encryption protects data confidentiality but doesn't prevent lateral movement within a network."}},
  {"id":98,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which security tool monitors endpoint devices for suspicious behavior and can automatically respond to contain a threat?","options":{"A":"Firewall","B":"IDS","C":"NAC","D":"EDR"},"correct_answer":"D","difficulty":2,"explanations":{"correct":"Endpoint Detection and Response (EDR) monitors endpoints for suspicious activity patterns and can automatically isolate compromised endpoints, kill malicious processes, and collect forensic data.","A":"Firewalls control network traffic but don't monitor endpoint process behavior.","B":"IDS monitors network traffic for intrusion signatures and alerts but typically doesn't take automated endpoint action.","C":"NAC enforces endpoint compliance before granting network access; it doesn't monitor for behavioral threats.","D":"Correct. EDR provides behavioral monitoring and automated response at the endpoint level."}},
  {"id":99,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"An organization wants to ensure devices meet security requirements (antivirus, patches, encryption) before connecting to the corporate network. Which solution BEST addresses this?","options":{"A":"IPS","B":"SIEM","C":"NAC","D":"DLP"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Network Access Control (NAC) enforces security policies at the point of network connection, checking device health (antivirus status, patch level, encryption) before allowing network access.","A":"IPS monitors for and blocks intrusion attempts in traffic; it doesn't assess device health before connection.","B":"SIEM aggregates and analyzes security logs; it doesn't control network admission.","C":"Correct. NAC enforces device health requirements as a condition of network access.","D":"DLP prevents unauthorized data exfiltration; it doesn't assess device security posture for admission."}},
  {"id":100,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which mitigation technique uses a curated list to specify which applications are permitted to run on a system?","options":{"A":"Blacklisting","B":"Allowlisting (application whitelisting)","C":"Sandboxing","D":"Signature-based detection"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Application allowlisting (whitelisting) permits only explicitly approved applications to execute, blocking all others by default. It is more effective than blacklisting because unknown/new malware is automatically blocked.","A":"Blacklisting (blocklisting) prevents known bad applications; unknown malware isn't caught.","B":"Correct. Allowlisting permits only approved applications, blocking all others including unknown malware.","C":"Sandboxing runs suspicious applications in an isolated environment for analysis; it's a detection/analysis technique.","D":"Signature-based detection identifies known malware patterns; allowlisting controls what can run regardless of signatures."}},
  {"id":101,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"A USB drive containing malware is left in a company parking lot. An employee finds it and plugs it in out of curiosity. Which technique does this attack rely on?","options":{"A":"Pretexting","B":"Baiting","C":"Quid pro quo","D":"Tailgating"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Baiting uses the promise or curiosity of something desirable (a found USB drive) to lure victims into taking a security-compromising action, such as plugging in the infected drive.","A":"Pretexting creates a fabricated scenario; baiting uses a physical lure.","B":"Correct. The USB drive left in a parking lot is the classic baiting attack scenario.","C":"Quid pro quo offers a service (like IT help) in exchange for information.","D":"Tailgating physically follows someone through a secure door."}},
  {"id":102,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which mobile device vulnerability occurs when sensitive data is stored in an unencrypted format on a device?","options":{"A":"Sideloading","B":"Insecure data storage","C":"Jailbreaking","D":"Bluesnarfing"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Insecure data storage stores sensitive information (credentials, PII, tokens) in plaintext in files, databases, or shared storage on a mobile device, making it accessible if the device is compromised.","A":"Sideloading installs apps from outside official app stores, increasing malware risk — a different vulnerability.","B":"Correct. Insecure data storage saves sensitive data without encryption on the device.","C":"Jailbreaking removes OS restrictions; while it increases risk, it is not itself a storage vulnerability.","D":"Bluesnarfing accesses data via Bluetooth without authorization — a network attack, not a storage issue."}},
  {"id":103,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"Which Bluetooth attack allows an unauthorized party to access data on a device without the owner's knowledge?","options":{"A":"Bluejacking","B":"Bluesnarfing","C":"Bluebugging","D":"Evil twin"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Bluesnarfing is unauthorized access to data (contacts, messages, calendar) on a Bluetooth-enabled device by exploiting Bluetooth vulnerabilities without the owner's knowledge or consent.","A":"Bluejacking sends unsolicited messages to Bluetooth devices but does not access data.","B":"Correct. Bluesnarfing steals data from Bluetooth devices without authorization.","C":"Bluebugging goes further than bluesnarfing — it allows the attacker to take control of calls and messages.","D":"Evil twin creates a fake Wi-Fi network, not a Bluetooth attack."}},
  {"id":104,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A large botnet sends millions of requests to a single website, overwhelming its servers. Which attack type is this?","options":{"A":"SQL injection","B":"Distributed Denial of Service (DDoS)","C":"APT","D":"MITM"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"A Distributed Denial of Service (DDoS) attack uses many compromised systems (botnet) to flood a target with traffic, overwhelming its capacity and making it unavailable to legitimate users.","A":"SQL injection manipulates database queries through input fields; not a flood attack.","B":"Correct. A botnet flooding a website with requests is a DDoS attack.","C":"APT is a long-term, stealthy attack campaign — not a volume-based availability attack.","D":"MITM intercepts communication between parties; not a traffic flood attack."}},
  {"id":105,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"A directory traversal attack allows an attacker to:","options":{"A":"Execute commands in the OS via web input","B":"Access files outside the intended web directory by manipulating file paths","C":"Inject malicious SQL into database queries","D":"Escalate privileges by exploiting misconfigured SUDO rules"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Directory traversal (path traversal) manipulates file path parameters (using ../ sequences) to access files and directories outside the web server's intended root directory.","A":"OS command execution via web input is command injection, not directory traversal.","B":"Correct. Directory traversal uses path manipulation to access files outside the intended directory.","C":"SQL injection targets database queries; directory traversal targets the file system.","D":"SUDO misconfiguration is a privilege escalation technique, not directory traversal."}},
  {"id":106,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"An administrator disables all unused services and closes unnecessary ports on a server. This hardening process is called:","options":{"A":"Patching","B":"Reducing the attack surface","C":"Defense in depth","D":"Network segmentation"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Reducing the attack surface involves eliminating unnecessary services, ports, accounts, and features that could be exploited. Fewer exposed components means fewer opportunities for attack.","A":"Patching applies security fixes to known vulnerabilities; it doesn't involve disabling services.","B":"Correct. Disabling unused services and ports reduces the attack surface.","C":"Defense in depth layers multiple controls; reducing attack surface is one technique that contributes to it.","D":"Network segmentation divides the network; disabling services on a server is host hardening."}},
  {"id":107,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"A malicious update to a widely-used software library is used to compromise thousands of downstream applications. This is a:","options":{"A":"Zero-day attack","B":"Watering hole attack","C":"Supply chain attack","D":"Insider threat"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"A supply chain attack targets a vendor, supplier, or software dependency to compromise downstream users. The SolarWinds attack is a famous example of a software supply chain attack.","A":"A zero-day exploits an unknown vulnerability; supply chain attacks may use known or unknown methods.","B":"A watering hole attack compromises sites visited by targets; supply chain attacks compromise the distribution pipeline.","C":"Correct. A malicious update distributed through a legitimate update channel is a supply chain attack.","D":"An insider threat originates from within the organization; a supply chain attack originates from an external vendor."}},
  {"id":108,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"An IDS alert shows repeated failed login attempts followed by a successful login from the same IP address. This BEST indicates:","options":{"A":"DNS tunneling","B":"Brute force attack","C":"SQL injection attempt","D":"ARP poisoning"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Multiple failed login attempts followed by a success from the same IP is the classic pattern of a brute force (or password spray) attack that eventually found valid credentials.","A":"DNS tunneling produces unusual DNS query patterns, not authentication failures.","B":"Correct. Repeated failed logins followed by success indicates a brute force attack.","C":"SQL injection appears in web application logs as malformed query strings, not authentication events.","D":"ARP poisoning shows unusual ARP traffic patterns, not authentication events."}},
  {"id":109,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which mitigation technique involves keeping software and operating systems up to date by applying vendor-released security fixes?","options":{"A":"Hardening","B":"Segmentation","C":"Patch management","D":"Allowlisting"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"Patch management is the systematic process of identifying, acquiring, testing, and installing security patches and updates to address known vulnerabilities in software and operating systems.","A":"Hardening involves reducing the attack surface by disabling features; patching fixes known vulnerabilities.","B":"Segmentation divides networks; it doesn't update software.","C":"Correct. Patch management applies vendor security fixes to address known vulnerabilities.","D":"Allowlisting controls which applications can run; it doesn't address patching vulnerabilities."}},
  {"id":110,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"An attacker intercepts a user's authentication token and uses it to impersonate the user for the remainder of the session. This is:","options":{"A":"Pass-the-hash","B":"Session hijacking","C":"CSRF","D":"Replay attack"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Session hijacking steals a valid session token (cookie, JWT, session ID) to impersonate an authenticated user, taking over an active session.","A":"Pass-the-hash specifically uses NTLM hashes in Windows environments; session hijacking applies broadly to web sessions.","B":"Correct. Stealing and using a session token to take over a user's session is session hijacking.","C":"CSRF forces a user to make an unintended request using their own session; hijacking steals the session.","D":"A replay attack retransmits captured authentication credentials; session hijacking reuses an active session token."}},
  {"id":111,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which vulnerability allows an attacker to inject malicious code into memory that is subsequently accessed after it has been freed?","options":{"A":"Buffer overflow","B":"Heap spray","C":"Use-after-free","D":"Integer overflow"},"correct_answer":"C","difficulty":4,"explanations":{"correct":"Use-after-free vulnerabilities occur when a program accesses memory that has been freed/deallocated. Attackers can fill the freed memory with malicious data before the vulnerable access occurs.","A":"Buffer overflow writes beyond allocated memory boundaries; use-after-free accesses freed memory.","B":"Heap spray fills the heap with shellcode to increase the likelihood of execution; a technique, not the vulnerability type.","C":"Correct. Use-after-free accesses memory after it has been deallocated, potentially executing attacker-controlled data.","D":"Integer overflow causes arithmetic to exceed its maximum value; unrelated to freed memory access."}},
  {"id":112,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker sends emails that appear to come from a legitimate internal IT department to targeted company employees. The email requests credentials for a 'system upgrade.' This is BEST described as:","options":{"A":"Whaling","B":"Phishing","C":"Spear phishing","D":"Vishing"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Spear phishing is a targeted phishing attack directed at specific individuals or organizations. The attacker researches the target to craft convincing, personalized emails.","A":"Whaling specifically targets executives (C-suite), not general employees.","B":"Generic phishing sends mass emails without personalization; this attack targets specific company employees.","C":"Correct. Targeted, personalized phishing against specific employees is spear phishing.","D":"Vishing uses voice calls; this attack uses email."}},
  {"id":113,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A process running on a server is connecting to an external IP address on an unusual port at regular intervals. This MOST likely indicates:","options":{"A":"Vulnerability scan","B":"DDoS participation","C":"Command and control (C2) beacon","D":"DNS zone transfer"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Regular outbound connections to external IPs on unusual ports at fixed intervals are characteristic of a C2 beacon — malware checking in with its command and control server for instructions.","A":"Vulnerability scans generate inbound probing traffic, not regular outbound connections to a single IP.","B":"DDoS participation would generate high-volume outbound traffic to many targets, not regular small connections to one IP.","C":"Correct. Regular beaconing to an external IP at fixed intervals strongly indicates C2 communication.","D":"DNS zone transfers are DNS protocol queries, not arbitrary IP connections on unusual ports."}},
  {"id":114,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which data loss prevention (DLP) strategy would BEST prevent employees from emailing sensitive files to personal email accounts?","options":{"A":"Full disk encryption","B":"Network-based DLP","C":"Endpoint DLP","D":"IDS alert"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Network-based DLP inspects outbound traffic (including email) for sensitive content and can block transmission of data matching defined policies, preventing emails containing sensitive data from leaving the network.","A":"Full disk encryption protects data at rest but does not prevent email exfiltration.","B":"Correct. Network DLP monitors and blocks email traffic containing sensitive data from leaving the organization.","C":"Endpoint DLP monitors data on devices and can also block email; however, network DLP is the most direct control for outbound email.","D":"IDS alerts on suspicious traffic but does not block it — it detects, not prevents."}},
  {"id":115,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"A web API endpoint does not validate the user's authorization before returning data, allowing any authenticated user to access other users' records. This is:","options":{"A":"Broken authentication","B":"Sensitive data exposure","C":"Broken object level authorization (BOLA/IDOR)","D":"Mass assignment"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Broken Object Level Authorization (BOLA), also known as Insecure Direct Object Reference (IDOR), occurs when an API endpoint fails to verify that the requesting user is authorized to access a specific object/record.","A":"Broken authentication relates to flaws in the authentication mechanism itself.","B":"Sensitive data exposure is a result of BOLA but is not the root cause.","C":"Correct. Accessing another user's object without authorization checking is BOLA/IDOR.","D":"Mass assignment allows clients to set object properties not intended to be user-settable."}},
  {"id":116,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A user reports that their browser is being redirected to unexpected websites. This MOST likely indicates which type of malware?","options":{"A":"Ransomware","B":"Browser hijacker","C":"Keylogger","D":"Rootkit"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Browser hijackers modify browser settings (homepage, search engine, DNS) to redirect users to attacker-controlled pages, often for advertising revenue or phishing.","A":"Ransomware encrypts files and demands payment; it doesn't typically redirect browsers.","B":"Correct. Browser redirection is the primary symptom of browser hijacker malware.","C":"Keyloggers record keystrokes silently; they don't cause browser redirections.","D":"Rootkits hide malware; they don't specifically redirect browsers as their primary symptom."}},
  {"id":117,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"Which attack type inserts malicious code into an HTTP response that executes in a victim's browser when they visit a page where other users' input is displayed?","options":{"A":"Reflected XSS","B":"Stored (persistent) XSS","C":"CSRF","D":"Clickjacking"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Stored XSS (persistent XSS) saves the malicious script in the server's database (e.g., in a forum post or comment). It executes in every visitor's browser when they view the infected page.","A":"Reflected XSS immediately returns the malicious input in a single response; it is not stored.","B":"Correct. Stored XSS persists malicious code in the database, affecting all page visitors.","C":"CSRF forces authenticated users to make unintended requests; it does not inject executable scripts.","D":"Clickjacking overlays invisible elements to trick users into clicking; it doesn't inject scripts."}},
  {"id":118,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Decommissioning end-of-life systems that can no longer be patched is PRIMARILY intended to:","options":{"A":"Increase network performance","B":"Reduce the attack surface","C":"Improve backup strategies","D":"Comply with data retention policies"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Decommissioning unsupported systems that can no longer receive patches removes permanently vulnerable systems from the network, directly reducing the attack surface.","A":"Removing systems may affect performance but that is not the security driver.","B":"Correct. Removing unpatched, end-of-life systems reduces the number of exploitable targets.","C":"Backup strategies are not the primary reason to decommission old systems.","D":"Data retention compliance may require keeping or deleting data but doesn't drive hardware decommissioning."}},
  {"id":119,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Firmware on a router contains a hardcoded debug account that cannot be disabled. This is BEST classified as:","options":{"A":"Default credentials","B":"Misconfiguration","C":"Backdoor","D":"Zero-day"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"A hardcoded debug account that cannot be disabled is a backdoor — an intentionally or negligently created hidden access mechanism that bypasses normal authentication.","A":"Default credentials are factory-set but changeable; a hardcoded account that cannot be disabled is a backdoor.","B":"Misconfiguration involves incorrect security settings; a hardcoded account is an inherent design flaw.","C":"Correct. A permanent, undocumented hardcoded account in firmware is a backdoor.","D":"Zero-day refers to unknown/unpatched vulnerabilities; a hardcoded account is a known design defect once discovered."}},
  {"id":120,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"An attacker sends a phishing link that, when clicked, silently makes a request to the victim's bank transferring funds, because the victim was already logged in. This is:","options":{"A":"Session hijacking","B":"XSS","C":"CSRF","D":"Clickjacking"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"CSRF exploits the trust a web application places in the user's browser. The attacker tricks the victim's authenticated browser into sending a forged request the victim did not intend to make.","A":"Session hijacking steals a session token for the attacker to use directly; CSRF exploits the victim's existing session.","B":"XSS injects scripts into pages; CSRF makes requests using the victim's session without script injection.","C":"Correct. CSRF tricks authenticated users into submitting unintended requests using their active session.","D":"Clickjacking tricks users into clicking overlaid UI elements; CSRF submits hidden requests."}},
  {"id":121,"domain":2,"subdomain":"2.1","objective":"Compare and contrast common threat actors and motivations","stem":"Which motivation is MOST commonly associated with hacktivist threat actors?","options":{"A":"Financial gain","B":"Espionage","C":"Ideology or political cause","D":"Personal revenge"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Hacktivists are motivated by ideology, political beliefs, or social causes. They use hacking to promote their cause, often targeting organizations they oppose.","A":"Financial gain motivates organized crime, not typically hacktivists.","B":"Espionage motivates nation-state actors.","C":"Correct. Hacktivists are ideologically and politically motivated.","D":"Personal revenge may motivate some insiders or individuals but not the hacktivist group category."}},
  {"id":122,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which technique prevents a rogue DHCP server from distributing unauthorized IP addresses on a network?","options":{"A":"ARP inspection","B":"DHCP snooping","C":"Port security","D":"802.1X"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"DHCP snooping is a switch security feature that distinguishes trusted DHCP server ports from untrusted ports, dropping DHCP offers from untrusted sources to prevent rogue DHCP servers.","A":"Dynamic ARP inspection validates ARP packets but targets ARP poisoning, not rogue DHCP.","B":"Correct. DHCP snooping blocks DHCP server responses from untrusted switch ports.","C":"Port security limits MAC addresses per port; it doesn't specifically block DHCP server responses.","D":"802.1X provides network access control via authentication but doesn't specifically block rogue DHCP."}},
  {"id":123,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"An organization wants to prevent employees from accessing social media during work hours on the corporate network. Which control BEST achieves this?","options":{"A":"IPS","B":"NAC","C":"Content/web filtering","D":"DLP"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Content/web filtering (proxy-based or DNS-based) inspects URLs and blocks access to categories like social media, enforcing acceptable use policies.","A":"IPS detects and blocks network attack signatures, not content category filtering.","B":"NAC controls network admission based on device health, not content access.","C":"Correct. Content/web filtering blocks access to prohibited website categories like social media.","D":"DLP prevents sensitive data from leaving the organization; it doesn't block access to websites."}},
  {"id":124,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"A web application allows users to access admin functions by changing a URL parameter from 'user=john' to 'user=admin'. This is:","options":{"A":"SQL injection","B":"Parameter tampering (IDOR)","C":"Privilege escalation via brute force","D":"Session fixation"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Insecure Direct Object Reference (IDOR) / parameter tampering allows users to modify parameters (URLs, form fields) to access unauthorized resources by changing reference values.","A":"SQL injection modifies database queries via input; this attack modifies URL parameters to change access level.","B":"Correct. Modifying a URL parameter to access another user's or admin's resources is IDOR/parameter tampering.","C":"Privilege escalation via brute force tries many credentials; this is a single parameter change.","D":"Session fixation forces a known session ID on a user before they authenticate."}},
  {"id":125,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker physically follows an authorized person through a badge-controlled door without badging in. This is called:","options":{"A":"Baiting","B":"Pretexting","C":"Tailgating","D":"Shoulder surfing"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"Tailgating (piggybacking) is physically following an authorized person through a secured entrance without using one's own credentials, exploiting courtesy or distraction.","A":"Baiting uses a lure (like a USB drive) to trick a victim.","B":"Pretexting creates a fake scenario to gain information or access.","C":"Correct. Physically following someone through a badge-controlled door without authenticating is tailgating.","D":"Shoulder surfing observes someone entering credentials by looking over their shoulder."}},
  {"id":126,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"An endpoint shows a new process that makes outbound connections, consumes unusual CPU resources, and is not listed in the installed software inventory. This MOST likely indicates:","options":{"A":"A legitimate system update","B":"Malware infection","C":"Hardware failure","D":"Network misconfiguration"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"An unrecognized process making outbound connections with unusual resource consumption is a strong indicator of malware (such as a RAT, miner, or C2 agent) that is not in the software inventory.","A":"Legitimate updates are known, listed, and typically use normal update channels.","B":"Correct. Unknown process with outbound connections and high resource use strongly indicates malware.","C":"Hardware failure would cause performance degradation, not new outbound network connections.","D":"Network misconfiguration affects connectivity, not process behavior or CPU usage."}},
  {"id":127,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which control specifically prevents the execution of code in memory regions marked as data (e.g., the stack)?","options":{"A":"ASLR","B":"DEP/NX (Data Execution Prevention)","C":"Stack canary","D":"Code signing"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Data Execution Prevention (DEP), also known as No-Execute (NX) bit, marks memory regions as non-executable. Code placed in data regions (stack/heap) cannot be executed, mitigating buffer overflow exploits.","A":"ASLR randomizes memory addresses to make exploit targets unpredictable; it doesn't mark regions as non-executable.","B":"Correct. DEP/NX prevents code execution in memory regions designated as data.","C":"Stack canaries are values placed before return addresses to detect stack overflows — detection, not execution prevention.","D":"Code signing verifies software authenticity before installation, not memory region executability."}},
  {"id":128,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which mitigation randomizes the location of executable, stack, and heap memory to make buffer overflow exploits harder to target?","options":{"A":"DEP","B":"Stack canary","C":"ASLR","D":"Sandboxing"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Address Space Layout Randomization (ASLR) randomizes the base addresses of stack, heap, and libraries at each execution, making it much harder for attackers to predict target memory addresses for exploits.","A":"DEP marks regions as non-executable; ASLR randomizes locations.","B":"Stack canaries detect stack overflows by monitoring a guard value; they don't randomize addresses.","C":"Correct. ASLR randomizes memory layout to defeat hardcoded exploit addresses.","D":"Sandboxing isolates application execution; it doesn't randomize memory layout."}},
  {"id":129,"domain":2,"subdomain":"2.1","objective":"Compare and contrast common threat actors and motivations","stem":"Which term describes the capabilities and resources available to a threat actor?","options":{"A":"Attack vector","B":"Threat landscape","C":"Attack surface","D":"Threat actor attributes (sophistication/capability)"},"correct_answer":"D","difficulty":2,"explanations":{"correct":"A threat actor's sophistication and capability (along with resources) describes what they are able to do — the complexity of attacks they can conduct and the tools/funding they have access to.","A":"An attack vector is the method or path used to gain access, not an actor's capabilities.","B":"The threat landscape describes the overall environment of threats; not an individual actor's capability.","C":"Attack surface refers to the total exposed area of a system, not an actor's resources.","D":"Correct. Sophistication and capability are the key attributes that differentiate threat actors."}},
  {"id":130,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A SIEM detects that a user downloaded 50GB of data at 2:00 AM and then connected to a foreign IP. This BEST indicates:","options":{"A":"Routine backup operation","B":"Data exfiltration by an insider or compromised account","C":"DDoS attack preparation","D":"Routine software update"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Large-scale data download at unusual hours followed by external IP connection is a classic data exfiltration indicator, suggesting insider threat or compromised account activity.","A":"Routine backups would go to known internal/backup systems, not external foreign IPs.","B":"Correct. Unusual data download volume followed by foreign IP connection strongly indicates data exfiltration.","C":"DDoS preparation involves botnet communication, not large downloads to foreign IPs.","D":"Routine updates download from known vendor infrastructure, not 50GB to foreign IPs."}},
  {"id":131,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which vulnerability specifically affects SCADA and ICS systems that were designed for isolated environments but are now internet-connected?","options":{"A":"Zero-day","B":"Legacy technology vulnerability","C":"Unsecure network configuration","D":"Air-gap circumvention"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"SCADA/ICS systems were designed for isolated operational technology environments without security considerations for internet connectivity. Connecting them to IP networks exposes design vulnerabilities in legacy industrial systems.","A":"Zero-days are unknown vulnerabilities; SCADA vulnerabilities are often known but unpatched or unpatchable.","B":"Correct. SCADA/ICS vulnerabilities are classic legacy technology issues — designed without modern security in mind.","C":"Unsecure network configuration is a subset of the problem but doesn't capture the full vulnerability scope.","D":"Air-gap circumvention (e.g., Stuxnet via USB) is an attack method, not the vulnerability classification."}},
  {"id":132,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"Which social engineering technique involves an attacker offering something valuable (like free tech support) in exchange for information?","options":{"A":"Pretexting","B":"Baiting","C":"Quid pro quo","D":"Tailgating"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Quid pro quo (this for that) attacks offer a benefit — typically a service like IT support — in exchange for information such as credentials. The classic example is a fake IT tech calling and offering help in exchange for a password.","A":"Pretexting fabricates a scenario to build trust; quid pro quo specifically offers something in exchange.","B":"Baiting uses a physical or digital lure without requiring an exchange.","C":"Correct. Quid pro quo exchanges a service or benefit for sensitive information.","D":"Tailgating is a physical security bypass technique."}},
  {"id":133,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"An analyst finds a file named 'svchost.exe' in the Downloads folder of a user's computer. The real svchost.exe resides in System32. What is MOST likely occurring?","options":{"A":"Legitimate Windows file in wrong location","B":"Masquerading — malware using a legitimate filename","C":"DLL hijacking","D":"Rootkit installation"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Masquerading involves malware naming itself after legitimate system processes (like svchost.exe) to avoid suspicion. A legitimate Windows process would not reside in the Downloads folder.","A":"Legitimate Windows processes do not reside in user Downloads folders; this is suspicious.","B":"Correct. Naming malware after a known system process to avoid detection is masquerading.","C":"DLL hijacking places a malicious DLL to intercept legitimate DLL loading; not a filename masquerade.","D":"Rootkit installation hides malware; while a rootkit could use this name, masquerading is the specific indicator here."}},
  {"id":134,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"A hospital must continue operating an end-of-life medical device that cannot be patched. Which mitigation is MOST appropriate?","options":{"A":"Replace the device immediately","B":"Implement network segmentation and strict firewall rules around the device","C":"Apply antivirus software to the device","D":"Encrypt all data on the device"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"When a critical system cannot be patched or replaced, compensating controls like network segmentation (isolating the device) with strict firewall rules reduce the risk of exploitation from adjacent systems.","A":"Replacing immediately may not be feasible for specialized medical equipment with regulatory requirements.","B":"Correct. Segmentation and firewall rules compensate for unpatched vulnerabilities by limiting exposure.","C":"End-of-life medical devices may not support modern antivirus and may not have detected signatures for relevant threats.","D":"Encryption addresses data confidentiality, not exploitation of unpatched vulnerabilities."}},
  {"id":135,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which attack exploits trust relationships by intercepting and modifying data between a web server and client before it reaches the browser?","options":{"A":"Reflected XSS","B":"SSL stripping","C":"CSRF","D":"DOM manipulation"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"SSL stripping (HTTP downgrade attack) intercepts HTTPS traffic and downgrades it to HTTP, allowing the attacker to read plaintext communications even when the server supports HTTPS.","A":"Reflected XSS injects scripts via crafted links; SSL stripping intercepts and downgrades encrypted connections.","B":"Correct. SSL stripping downgrades HTTPS to HTTP to expose traffic to interception.","C":"CSRF forces unintended requests using a user's session; it doesn't downgrade encryption.","D":"DOM manipulation modifies web page structure; it doesn't involve connection downgrade."}},
  {"id":136,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"A company's newly acquired subsidiary uses a different security framework and has less mature security controls, creating risk for the parent company. This is an example of:","options":{"A":"Shadow IT","B":"Supply chain risk","C":"Multiparty risk","D":"Regulatory compliance gap"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Multiparty risk arises when an organization's security is dependent on or interconnected with another party (partner, acquisition, subsidiary) that may have different security standards or weaker controls.","A":"Shadow IT is unauthorized use of technology; an acquired subsidiary is a formal business entity.","B":"Supply chain risk specifically relates to vendors, suppliers, or software dependencies.","C":"Correct. Security risk arising from interdependencies with another organization (acquisition) is multiparty risk.","D":"Regulatory compliance gaps are part of the risk but don't capture the interconnected party aspect."}},
  {"id":137,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A user's computer is performing very slowly, the fan is running constantly, and network usage is high even when the computer is idle. This MOST likely indicates:","options":{"A":"Ransomware encryption in progress","B":"Cryptominer malware","C":"Keylogger operation","D":"Rootkit installation"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Cryptomining malware uses the victim's CPU and GPU for cryptocurrency mining, causing high CPU usage, fan activity, and may also have C2 network traffic — exactly matching the described symptoms.","A":"Ransomware encryption causes high disk I/O and CPU during encryption, but network usage is typically lower.","B":"Correct. High CPU, fan noise, and idle network usage are classic cryptominer indicators.","C":"Keyloggers are lightweight and don't cause significant CPU or network overhead.","D":"Rootkit installation is a one-time event; ongoing high resource usage is more consistent with a running miner."}},
  {"id":138,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which technique would BEST prevent an attacker from using harvested credentials from one breach to log into other services?","options":{"A":"Password complexity requirements","B":"Multi-factor authentication (MFA)","C":"Account lockout after failed attempts","D":"Password length minimum"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"MFA requires a second factor beyond the password. Even if credentials from a breach are valid, the attacker cannot authenticate without the second factor (token, biometric, authenticator app).","A":"Password complexity doesn't help when the actual correct password has been stolen.","B":"Correct. MFA prevents use of stolen credentials by requiring a second authentication factor.","C":"Account lockout helps against brute force but not against valid stolen credentials being used correctly.","D":"Longer passwords don't help if the actual password was stolen in plaintext."}},
  {"id":139,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A file on a user's desktop has a .pdf extension but its MIME type is identified as application/x-msdownload. This is MOST likely:","options":{"A":"A corrupted PDF file","B":"A malicious file using a double extension to disguise its type","C":"A misconfigured browser download","D":"A legitimate PDF opened as executable"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Files masquerading as one type (using a misleading extension like .pdf) but with a different actual MIME type (executable) are a classic malware delivery technique — the file is designed to look safe but executes as a program.","A":"Corrupted PDF files would show PDF-related MIME types or errors, not executable MIME types.","B":"Correct. Extension mismatch with executable MIME type indicates a file masquerading as a document.","C":"Browser misconfiguration doesn't change a file's MIME type.","D":"PDF files opened as executables would be an OS misconfiguration, not explained by MIME type mismatch."}},
  {"id":140,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"A developer uses a third-party open-source library with a known critical vulnerability that has not been updated. This is BEST classified as:","options":{"A":"Zero-day vulnerability","B":"Known vulnerability in third-party software","C":"Misconfiguration","D":"Default credentials"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Using an outdated third-party library with a known (disclosed) vulnerability that has an available patch is a known unpatched vulnerability in third-party software — a supply chain and patch management issue.","A":"Zero-days are unknown/unpatched by the vendor; a known CVE with an available patch is not a zero-day.","B":"Correct. A known CVE in a third-party library that hasn't been updated is an unpatched third-party vulnerability.","C":"Misconfiguration is an incorrect security setting, not a software library vulnerability.","D":"Default credentials involve authentication settings, not software library vulnerabilities."}},
  {"id":141,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"A malicious image file is crafted to exploit a vulnerability in an image viewer when opened. Which attack vector does this represent?","options":{"A":"Phishing","B":"Image-based attack","C":"File-based malware delivery","D":"Drive-by download"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Malicious files (images, documents, PDFs) that exploit vulnerabilities in the applications that open them are file-based attack vectors. The file itself is the attack delivery mechanism.","A":"Phishing is the delivery method (email) but the file itself represents a file-based vector.","B":"Image-based attack is a subset of file-based attack; both are acceptable but file-based is the more precise classification for SY0-701.","C":"Correct. A malicious file exploiting a viewer vulnerability is a file-based attack vector.","D":"Drive-by downloads occur via web browsing without user file interaction; this requires opening the file."}},
  {"id":142,"domain":2,"subdomain":"2.1","objective":"Compare and contrast common threat actors and motivations","stem":"Which attribute describes a threat actor's ability to conduct attacks without being detected over long periods?","options":{"A":"Sophistication","B":"Operational security (OPSEC)","C":"Resources","D":"Motivation"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Operational security (OPSEC) refers to the attacker's ability to conduct operations without detection. Nation-states and organized crime often have strong OPSEC, enabling long-term undetected access.","A":"Sophistication describes technical skill level, not specifically stealth capability.","B":"Correct. OPSEC describes the attacker's ability to remain undetected during operations.","C":"Resources include funding, personnel, and tools — not specifically about stealth.","D":"Motivation is the reason for the attack, not the operational capability."}},
  {"id":143,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"SPF, DKIM, and DMARC records are configured in DNS to protect against which threat?","options":{"A":"DNS cache poisoning","B":"Email spoofing and phishing","C":"BGP hijacking","D":"Domain typosquatting"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"SPF (Sender Policy Framework), DKIM (DomainKeys Identified Mail), and DMARC (Domain-based Message Authentication) work together to authenticate email senders and prevent spoofing and phishing using legitimate domain names.","A":"DNS cache poisoning targets DNS resolver caches; SPF/DKIM/DMARC address email authentication.","B":"Correct. SPF, DKIM, and DMARC prevent email spoofing by authenticating legitimate senders.","C":"BGP hijacking manipulates internet routing; unrelated to email authentication.","D":"Typosquatting registers fake domains; DMARC protects the legitimate domain from being spoofed."}},
  {"id":144,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A vulnerability scanner detects an open port 4444 listening on a server. This port is commonly associated with which malware?","options":{"A":"Ransomware","B":"Metasploit Meterpreter default listener","C":"Cryptominer","D":"Keylogger"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Port 4444 is the default listener port for Metasploit's Meterpreter payload. Its presence on a server is a strong indicator of a compromised system running a Meterpreter reverse shell.","A":"Ransomware encrypts files; it doesn't typically open port 4444 as a listener.","B":"Correct. Port 4444 is the default Metasploit/Meterpreter listener port — a major red flag.","C":"Cryptominers communicate with mining pools on specific mining protocol ports, not 4444.","D":"Keyloggers send data to C2 servers but use varied ports, not specifically 4444."}},
  {"id":145,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which technique makes the analysis of malware more difficult by having the malicious code change its binary signature with each infection?","options":{"A":"Fileless malware","B":"Polymorphic malware","C":"Metamorphic malware","D":"Armored malware"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Polymorphic malware changes its signature (encrypts or transforms its code) with each infection cycle while maintaining the same core functionality, defeating signature-based antivirus detection.","A":"Fileless malware operates in memory without writing files; it doesn't change its binary signature.","B":"Correct. Polymorphic malware mutates its code signature with each infection to evade signature detection.","C":"Metamorphic malware rewrites its entire code (not just encrypts it), making it even harder to detect.","D":"Armored malware uses anti-debugging and anti-analysis techniques to resist examination."}},
  {"id":146,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker sends an email with a link that, when clicked, takes the victim to a fake but convincing bank login page. This is:","options":{"A":"Pharming","B":"Phishing","C":"Spoofing","D":"Smishing"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"Phishing uses fraudulent emails with malicious links that direct victims to fake websites designed to steal credentials. It is the most common social engineering attack delivered via email.","A":"Pharming redirects users from legitimate websites to fraudulent ones via DNS manipulation, not a direct email link.","B":"Correct. Fraudulent email with a fake login link is the classic phishing scenario.","C":"Spoofing disguises the attacker's identity (email address, IP) — it is part of phishing but not the attack type itself.","D":"Smishing uses SMS text messages; this attack uses email."}},
  {"id":147,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"Which indicator BEST suggests that a threat actor has achieved persistence on a compromised system?","options":{"A":"A single failed login attempt","B":"A new scheduled task running encoded PowerShell at startup","C":"An unusual website visit in browser history","D":"High CPU usage during a software update"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"A new scheduled task running encoded PowerShell at startup is a classic persistence mechanism — attackers create scheduled tasks, registry run keys, or services to survive reboots.","A":"A single failed login is not necessarily malicious and doesn't indicate persistence.","B":"Correct. A new startup scheduled task with encoded PowerShell is a strong persistence indicator.","C":"An unusual website visit could be social engineering-related but doesn't indicate system persistence.","D":"High CPU during updates is expected behavior and not a persistence indicator."}},
  {"id":148,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"An API endpoint is vulnerable because it processes XML input that includes external entity references, potentially exposing internal files or performing server-side requests. This is:","options":{"A":"SQL injection","B":"XML External Entity (XXE) injection","C":"SSRF","D":"Command injection"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"XXE (XML External Entity) injection occurs when an XML parser processes external entity references in user-supplied XML, potentially disclosing files, causing SSRF, or enabling DoS attacks.","A":"SQL injection targets database queries, not XML parsing.","B":"Correct. XXE exploits XML parsers that process external entity references in user input.","C":"Server-Side Request Forgery (SSRF) forces the server to make requests; XXE can cause SSRF but is the specific vulnerability type here.","D":"Command injection targets OS command interpreters, not XML processors."}},
  {"id":149,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A DLP alert triggers when an employee attempts to upload a file containing credit card numbers to a personal cloud storage account. This is an indicator of:","options":{"A":"Policy violation and potential data exfiltration","B":"Ransomware infection","C":"Insider threat establishing persistence","D":"Phishing attempt"},"correct_answer":"A","difficulty":2,"explanations":{"correct":"Attempting to upload sensitive data (credit card numbers) to personal cloud storage violates data handling policies and is a data exfiltration indicator, whether intentional or accidental.","A":"Correct. Uploading sensitive data to personal storage is both a policy violation and exfiltration indicator.","B":"Ransomware encrypts files; uploading to personal storage is exfiltration.","C":"Persistence involves maintaining system access; data upload is exfiltration.","D":"Phishing involves deceiving others; this is data exfiltration behavior."}},
  {"id":150,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which mitigation technique involves verifying that file hashes match known-good values to detect unauthorized changes?","options":{"A":"DLP","B":"File integrity monitoring (FIM)","C":"ACL","D":"Vulnerability scanning"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"File Integrity Monitoring (FIM) computes and stores baseline file hashes, then regularly compares current hashes against the baseline to detect unauthorized modifications to critical files.","A":"DLP prevents data exfiltration; it doesn't verify file integrity via hashing.","B":"Correct. FIM uses cryptographic hashes to detect unauthorized file changes.","C":"ACLs control who can access files; they don't detect changes made by authorized users.","D":"Vulnerability scanning identifies known vulnerabilities in software; it doesn't monitor for file changes."}},
  {"id":151,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which vulnerability type occurs when a web application server is tricked into making HTTP requests to internal resources on behalf of the attacker?","options":{"A":"XXE","B":"CSRF","C":"SSRF","D":"Open redirect"},"correct_answer":"C","difficulty":4,"explanations":{"correct":"Server-Side Request Forgery (SSRF) causes a server to make requests to internal resources (internal APIs, cloud metadata endpoints) that the attacker cannot directly access from outside.","A":"XXE involves XML external entity processing; SSRF involves arbitrary server-side HTTP requests.","B":"CSRF tricks a user's browser into making requests; SSRF tricks the server itself.","C":"Correct. SSRF forces the server to make requests to internal targets on the attacker's behalf.","D":"Open redirect redirects users to external URLs; SSRF targets internal server-side requests."}},
  {"id":152,"domain":2,"subdomain":"2.1","objective":"Compare and contrast common threat actors and motivations","stem":"An employee repeatedly accesses sensitive HR files unrelated to their job out of curiosity, not to cause harm. This is BEST classified as:","options":{"A":"Malicious insider","B":"Unintentional insider","C":"Nation-state actor","D":"Shadow IT"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"An unintentional insider causes harm or risk through carelessness, curiosity, or policy violations without malicious intent. Accessing files out of curiosity without malicious purpose fits this category.","A":"A malicious insider deliberately intends to cause harm or gain unauthorized benefit.","B":"Correct. Accessing files from curiosity without malicious intent is an unintentional insider behavior.","C":"Nation-state actors are external, government-sponsored threat groups.","D":"Shadow IT involves using unauthorized technology tools, not unauthorized data access."}},
  {"id":153,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker exploits a misconfigured cloud storage bucket that is publicly accessible, exposing customer data. Which attack surface does this represent?","options":{"A":"Network attack surface","B":"Cloud attack surface","C":"Physical attack surface","D":"Social engineering attack surface"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Misconfigured cloud resources (public S3 buckets, open APIs) are part of the cloud attack surface. Cloud misconfigurations are among the most common causes of data breaches.","A":"Network attack surface refers to exposed network services and ports; cloud misconfiguration is specifically a cloud attack surface issue.","B":"Correct. Publicly exposed cloud storage is a cloud attack surface vulnerability.","C":"Physical attack surface involves physical access to hardware.","D":"Social engineering targets people, not cloud infrastructure."}},
  {"id":154,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A Windows event log shows Event ID 4625 (failed logon) repeated hundreds of times for the same account followed by Event ID 4624 (successful logon). This indicates:","options":{"A":"Normal password reset process","B":"Successful brute force or password spray attack","C":"Account provisioning","D":"MFA authentication failure"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Multiple failed logon attempts (4625) followed by a successful logon (4624) for the same account is the signature event sequence of a successful brute force or password spray attack.","A":"Password resets follow a different sequence (4723, 4724) and don't involve repeated failures.","B":"Correct. Repeated 4625 events followed by 4624 is the classic brute force success pattern.","C":"Account provisioning events show account creation (4720), not repeated login failures.","D":"MFA failures would appear in authentication logs but don't explain hundreds of 4625 events followed by 4624."}},
  {"id":155,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which approach to software security testing sends random, malformed, or unexpected inputs to an application to discover crashes and vulnerabilities?","options":{"A":"SAST","B":"DAST","C":"Fuzzing","D":"Code review"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Fuzzing (fuzz testing) automatically sends large quantities of random, malformed, or unexpected data to application inputs to discover crashes, unexpected behavior, and vulnerabilities like buffer overflows.","A":"SAST (Static Application Security Testing) analyzes source code for vulnerabilities without execution.","B":"DAST (Dynamic Application Security Testing) tests running applications but follows defined test cases, not random inputs.","C":"Correct. Fuzzing uses random/unexpected inputs to discover crashes and vulnerabilities.","D":"Code review manually examines code for issues; it is not automated input generation."}},
  {"id":156,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which vulnerability class represents weaknesses in AI model training data that cause incorrect or biased outputs?","options":{"A":"Prompt injection","B":"Model poisoning","C":"Hallucination","D":"Adversarial input"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Model (data) poisoning injects malicious training data into an AI model's dataset to cause the model to produce incorrect, biased, or attacker-desired outputs.","A":"Prompt injection manipulates AI model behavior through crafted inputs during inference, not training.","B":"Correct. Model poisoning corrupts the training data to influence model behavior.","C":"Hallucination is AI producing confident but incorrect outputs — a reliability issue, not a security attack.","D":"Adversarial inputs manipulate AI decisions at inference time using specially crafted inputs."}},
  {"id":157,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"Which network-level attack sends a packet with source and destination IP both set to the target's IP address, causing the system to reply to itself?","options":{"A":"Smurf attack","B":"Land attack","C":"Ping of death","D":"Teardrop attack"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"A Land attack sends a TCP SYN packet with the source IP spoofed to match the destination IP. The system attempts to respond to itself, creating an infinite loop that can crash older systems.","A":"A Smurf attack sends broadcast ICMP requests with a spoofed source IP; different mechanism.","B":"Correct. A Land attack uses the same IP for source and destination, causing self-looping.","C":"Ping of death sends oversized ICMP packets.","D":"A Teardrop attack sends fragmented packets with overlapping offsets."}},
  {"id":158,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which security configuration on a switch prevents a single device from flooding the switch MAC table and causing all traffic to be broadcast?","options":{"A":"DHCP snooping","B":"Port security","C":"802.1X","D":"VTP pruning"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Port security limits the number of MAC addresses allowed on a switch port. If the limit is exceeded, the port can be shut down, preventing MAC flooding attacks.","A":"DHCP snooping controls DHCP server traffic, not MAC address flooding.","B":"Correct. Port security limits MAC addresses per port, preventing MAC table flooding.","C":"802.1X provides port-based authentication; it doesn't limit MAC addresses.","D":"VTP pruning controls VLAN advertisement propagation; unrelated to MAC flooding."}},
  {"id":159,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"Which category of indicator involves observing unexpected outbound data transfers and connections to unfamiliar external IP addresses?","options":{"A":"Physical indicator","B":"Host-based indicator","C":"Network-based indicator","D":"Application-based indicator"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Network-based indicators of compromise (IoCs) include unusual outbound traffic, connections to known-bad IPs, unusual data transfer volumes, and unexpected protocol usage on network segments.","A":"Physical indicators involve physical evidence of tampering (broken seals, moved equipment).","B":"Host-based indicators include new processes, modified files, registry changes, and unusual account activity on the endpoint.","C":"Correct. Unusual outbound connections and data transfers are network-based IoCs.","D":"Application-based indicators include unusual application behavior, error logs, or unexpected API calls."}},
  {"id":160,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which approach tests all software components in isolation using automated tests to ensure individual functions work correctly?","options":{"A":"Integration testing","B":"Regression testing","C":"Unit testing","D":"Penetration testing"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Unit testing verifies that individual functions or components of code work correctly in isolation from the rest of the system, typically using automated test cases written by developers.","A":"Integration testing verifies that multiple components work together correctly.","B":"Regression testing ensures new code changes haven't broken existing functionality.","C":"Correct. Unit testing tests individual functions/components in isolation.","D":"Penetration testing simulates attacks to find vulnerabilities; it's not a code-level testing technique."}},
  {"id":161,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker compromises an MSP (Managed Service Provider) and uses the MSP's trusted remote access to attack the MSP's clients. This is BEST classified as:","options":{"A":"Watering hole attack","B":"Insider threat","C":"Supply chain attack (trusted third-party)","D":"APT"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Compromising a trusted third-party (like an MSP) to attack its clients through trusted access channels is a supply chain attack. The SolarWinds and Kaseya attacks are real examples of this vector.","A":"A watering hole targets websites frequented by a victim group; this targets a service provider.","B":"Insider threat comes from within the victimized organization; MSP compromise is external.","C":"Correct. Using a compromised trusted third party to attack clients is a supply chain attack.","D":"APT is a sophisticated, persistent campaign; it can use this vector but is not the vector itself."}},
  {"id":162,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which vulnerability occurs when an attacker can manipulate an application to execute operating system commands through user input?","options":{"A":"SQL injection","B":"LDAP injection","C":"Command injection","D":"Template injection"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Command injection occurs when an application passes unsanitized user input to an OS command interpreter (shell), allowing attackers to execute arbitrary system commands.","A":"SQL injection targets database query interpreters, not OS shells.","B":"LDAP injection manipulates LDAP directory queries.","C":"Correct. Command injection allows execution of arbitrary OS commands via unsanitized input.","D":"Template injection exploits server-side template engines to execute code."}},
  {"id":163,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A security tool detects that an executable is connecting to an IP address that appears on multiple threat intelligence blacklists. This is an indicator of:","options":{"A":"False positive","B":"Connection to a known malicious command and control server","C":"Legitimate software update","D":"Network scanning activity"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"An executable connecting to a blacklisted IP is a strong indicator of malware communicating with a known command and control (C2) server. Threat intelligence feeds identify IPs associated with malicious activity.","A":"While false positives exist, an executable connecting to a blacklisted IP requires investigation and is not assumed false positive.","B":"Correct. Connection to a threat intelligence-listed IP strongly indicates C2 communication.","C":"Legitimate software connects to known vendor infrastructure, not threat intelligence blacklisted IPs.","D":"Network scanning generates broad probe traffic, not connections to specific blacklisted IPs."}},
  {"id":164,"domain":2,"subdomain":"2.1","objective":"Compare and contrast common threat actors and motivations","stem":"Which term describes a threat actor's level of technical expertise and tool development capability?","options":{"A":"Attack vector","B":"Threat intelligence","C":"Sophistication","D":"Motive"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Sophistication describes a threat actor's technical skill level, ability to develop custom tools, and capability to conduct complex operations. Nation-states are typically highly sophisticated.","A":"Attack vector is the method of attack delivery, not the actor's skill level.","B":"Threat intelligence is information about threats and actors; sophistication is an actor attribute.","C":"Correct. Sophistication measures a threat actor's technical expertise and tool development capability.","D":"Motive is the reason for attacking; sophistication is the capability to execute attacks."}},
  {"id":165,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which security control specifically monitors and restricts what privileged users and service accounts can do on critical systems?","options":{"A":"IDS","B":"DLP","C":"Privileged Access Management (PAM)","D":"SIEM"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Privileged Access Management (PAM) controls, monitors, and audits privileged user and service account access to critical systems, implementing just-in-time access, session recording, and credential vaulting.","A":"IDS monitors network traffic for intrusion indicators; it doesn't manage privileged access.","B":"DLP prevents data exfiltration; it doesn't manage privileged account access.","C":"Correct. PAM specifically addresses privileged account management, monitoring, and restriction.","D":"SIEM aggregates and analyzes logs; while it can alert on privileged access events, it doesn't manage them."}},
  {"id":166,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"A vulnerability exists because a function processes signed integers, allowing a negative number to pass a 'length > 0' check and causing unexpected behavior. This is:","options":{"A":"Buffer overflow","B":"Integer overflow","C":"Type confusion","D":"Off-by-one error"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Integer overflow (or signed integer misuse) occurs when arithmetic operations exceed the integer's range or when signed/unsigned conversion causes unexpected values. Negative numbers passing positive length checks is a classic example.","A":"Buffer overflow writes past memory boundaries; this is an arithmetic/type issue with the integer.","B":"Correct. Signed integer misuse causing unexpected values is an integer overflow/underflow vulnerability.","C":"Type confusion exploits incorrect assumptions about object types; this is specifically an integer sign issue.","D":"An off-by-one error uses one element beyond bounds; different from signed integer issues."}},
  {"id":167,"domain":2,"subdomain":"2.2","objective":"Explain common threat vectors and attack surfaces","stem":"An attacker identifies and exploits a misconfigured cloud IAM policy that grants all authenticated AWS users access to sensitive S3 buckets. Which attack surface is exploited?","options":{"A":"Network attack surface","B":"Software attack surface","C":"Cloud attack surface","D":"Physical attack surface"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Misconfigured cloud IAM policies and storage permissions represent the cloud attack surface — vulnerabilities specific to cloud platform configuration and identity management.","A":"Network attack surface concerns exposed network services and ports.","B":"Software attack surface involves vulnerabilities in application code.","C":"Correct. Misconfigured cloud IAM is a cloud attack surface vulnerability.","D":"Physical attack surface involves physical access to hardware."}},
  {"id":168,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"An analyst notices a Windows registry Run key containing a base64-encoded PowerShell command. This MOST likely indicates:","options":{"A":"Legitimate system configuration","B":"Persistence mechanism with obfuscated payload","C":"Windows Update process","D":"Software installation"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Attackers frequently use base64-encoded PowerShell commands in registry Run keys as a persistence and obfuscation technique. The encoding hides the payload from casual inspection and signature detection.","A":"Legitimate software uses readable registry entries for startup; base64-encoded commands are suspicious.","B":"Correct. Base64-encoded PowerShell in a Run key is a classic malware persistence and obfuscation technique.","C":"Windows Update uses standard service mechanisms, not encoded PowerShell in registry Run keys.","D":"Software installation uses installer-based startup entries, not encoded commands."}},
  {"id":169,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"An organization implements a rule requiring every access request to include user identity verification regardless of network location. This implements which principle?","options":{"A":"Defense in depth","B":"Zero trust","C":"Least privilege","D":"Separation of duties"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Zero trust requires verification of every access request regardless of network location, eliminating implicit trust based on being inside the network perimeter.","A":"Defense in depth layers security controls; zero trust is the specific framework requiring continuous verification.","B":"Correct. Verifying all access requests regardless of location is zero trust architecture.","C":"Least privilege limits access scope; zero trust addresses the verification requirement.","D":"Separation of duties divides tasks; it is not about access verification."}},
  {"id":170,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"Which log source would BEST show evidence of lateral movement between Windows systems using pass-the-hash?","options":{"A":"Web server access logs","B":"Windows Security Event Log (Event IDs 4624, 4648)","C":"DNS query logs","D":"Firewall logs"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Windows Security Event Logs record authentication events. Pass-the-hash lateral movement appears as Type 3 (Network) logons (4624) and explicit credential logons (4648) using NTLM from unexpected source machines.","A":"Web server logs record HTTP access; pass-the-hash is a Windows authentication attack.","B":"Correct. Event ID 4624 (logon) with Type 3/NTLM and 4648 (explicit credential use) show pass-the-hash lateral movement.","C":"DNS logs show name resolution activity; they don't record authentication events.","D":"Firewall logs show network connections; they don't record authentication details."}},
  {"id":171,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which type of injection attack manipulates directory service queries by inserting special characters into LDAP queries?","options":{"A":"SQL injection","B":"LDAP injection","C":"XPath injection","D":"Command injection"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"LDAP injection inserts special characters into LDAP queries to bypass authentication, access unauthorized directory data, or enumerate directory entries — similar to SQL injection but targeting LDAP directories.","A":"SQL injection targets database queries, not directory service queries.","B":"Correct. LDAP injection manipulates LDAP directory queries through unsanitized input.","C":"XPath injection targets XML document queries; LDAP injection targets directory services.","D":"Command injection targets OS shells, not directory service queries."}},
  {"id":172,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"Which control prevents an attacker from using stolen TLS session keys to decrypt previously captured encrypted traffic?","options":{"A":"Certificate pinning","B":"HSTS","C":"Perfect Forward Secrecy (PFS)","D":"OCSP stapling"},"correct_answer":"C","difficulty":4,"explanations":{"correct":"Perfect Forward Secrecy (PFS) generates unique session keys for each connection. If a private key is later compromised, previously captured traffic cannot be decrypted because each session used a different ephemeral key.","A":"Certificate pinning validates expected certificates; it doesn't protect previously captured traffic.","B":"HSTS enforces HTTPS connections; it doesn't protect captured traffic.","C":"Correct. PFS ensures that compromising long-term keys doesn't expose past session traffic.","D":"OCSP stapling provides certificate status; it doesn't protect past traffic."}},
  {"id":173,"domain":2,"subdomain":"2.4","objective":"Analyze indicators of malicious activity","stem":"A security analyst observes that a legitimate signed binary (e.g., rundll32.exe) is loading an unsigned DLL from an unusual directory. This MOST likely indicates:","options":{"A":"Software update in progress","B":"DLL hijacking or side-loading","C":"Normal Windows operation","D":"Driver installation"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"DLL hijacking places a malicious DLL in a location that a legitimate binary searches before the legitimate DLL path. The trusted binary loads and executes the malicious DLL, evading application allowlisting.","A":"Software updates use signed DLLs from known locations, not unsigned DLLs from unusual directories.","B":"Correct. A legitimate binary loading an unsigned DLL from an unexpected path is a DLL hijacking indicator.","C":"Normal Windows operation uses signed DLLs from System32 or known paths.","D":"Driver installation also uses signed binaries and known paths."}},
  {"id":174,"domain":2,"subdomain":"2.5","objective":"Explain the purpose of mitigation techniques","stem":"An organization requires all DNS queries from internal hosts to be sent to a controlled DNS resolver that blocks known-malicious domains. This is called:","options":{"A":"DNS over HTTPS (DoH)","B":"DNSSEC","C":"DNS sinkholing","D":"DNS filtering"},"correct_answer":"D","difficulty":2,"explanations":{"correct":"DNS filtering intercepts and blocks DNS queries for known-malicious domains, preventing connections to C2 servers, phishing sites, and malware distribution sites at the DNS level.","A":"DNS over HTTPS encrypts DNS queries to protect privacy; it doesn't block malicious domains by itself.","B":"DNSSEC validates DNS records using cryptographic signatures; it doesn't block malicious domains.","C":"DNS sinkholing redirects malicious domain queries to a controlled IP for analysis; DNS filtering is the broader category.","D":"Correct. DNS filtering blocks known-malicious domains at the DNS resolution level."}},
  {"id":175,"domain":2,"subdomain":"2.3","objective":"Explain various types of vulnerabilities","stem":"Which type of vulnerability is unique to containerized environments and occurs when a process escapes the container boundary and accesses the host OS?","options":{"A":"Hypervisor escape","B":"Container escape","C":"Privilege escalation","D":"Kernel exploit"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Container escape vulnerabilities allow a process inside a container to break out of the container's isolation and access the host OS or other containers, due to container runtime vulnerabilities or misconfigurations.","A":"Hypervisor escape breaks out of a virtual machine to the hypervisor/host; containers use a different isolation mechanism.","B":"Correct. Container escape breaks out of container isolation to access the host OS.","C":"Privilege escalation increases access within a system; container escape crosses isolation boundaries.","D":"Kernel exploits target the OS kernel; container escapes may use kernel vulnerabilities but the vulnerability type is container escape."}},
]
